mbr.copysrc:
     /* =================================================================== */
     /*                                                                     */
     /*  Documentation:                                                     */
     /*                                                                     */
     /*  Utility . . . : RUNCLSTM                                           */
     /*  Object  . . . : A_INSTALL  (PGM)                                   */
     /*  Source member : A_INSTALL                                          */
     /*  Source type . : CLLE                                               */
     /*  Description   : RUNCLSTM - Installer                               */
     /*  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      */
     /*  Created . . . :                                                    */
     /*                                                                     */
     /* =================================================================== */
     /*                                                                     */
     /*  This software is free software, you can redistribute it and/or     */
     /*  modify it under the terms of the GNU General Public License (GPL)  */
     /*  as published by the Free Software Foundation.                      */
     /*                                                                     */
     /*  See GNU General Public License for details.                        */
     /*          http://www.opensource.org                                  */
     /*          http://www.opensource.org/licenses/gpl-license.html        */
     /*                                                                     */
     /* =================================================================== */
     /*  History:                                                           */
     /*                                                                     */
     /*  Datum       Name          Änderung                                 */
     /*  ----------  ------------  ---------------------------------------  */
     /*                                                                     */
     /* =================================================================== */
     /*   >>PRE-COMPILER<<                                                  */
     /*     >>CRTCMD<<    CRTBNDCL  PGM(QTEMP/&OB) +                        */
     /*                             SRCFILE(&SL/&SF) SRCMBR(&SM);           */
     /*     >>IMPORTANT<<                                                   */
     /*       >>PARM<<    OPTION(*EVENTF);                                  */
     /*     >>END-IMPORTANT<<                                               */
     /*     >>EXECUTE<<                                                     */
     /*     >>CMD<<       CALL   PGM(QTEMP/A_INSTALL) +                     */
     /*                          PARM('*CURRENT' '&SF' '&LI' 'GER');        */
     /*     >>CMD<<       DLTPGM PGM(QTEMP/A_INSTALL);                      */
     /*   >>END-PRE-COMPILER<<                                              */
     /* =================================================================== */
             PGM        PARM(&TGTRLS &SRCFILE &TOLIB &LNG)

             DCL        VAR(&TGTRLS   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&SRCFILE  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&TOLIB    ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&LNG      ) TYPE(*CHAR) LEN( 3)

             DCL        VAR(&SRCLIB   ) TYPE(*CHAR) LEN(10)

             DCL        VAR(&CRTMSGF  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&MSGF     ) TYPE(*CHAR) LEN(10) VALUE('RUNCLSTM')
             DCL        VAR(&PNLGRP   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&CMD      ) TYPE(*CHAR) LEN(10)

             CHGVAR     VAR(&SRCLIB) VALUE(&TOLIB   )

     /* -------------------------------- */
     /*  Set language values             */
     /* -------------------------------- */
             IF         COND(&LNG *EQ 'ENG') THEN(DO)
                CHGVAR     VAR(&CRTMSGF) VALUE('A_MSG_ENG')
                CHGVAR     VAR(&PNLGRP ) VALUE('RUNCLSTMPE')
                CHGVAR     VAR(&CMD    ) VALUE('RUNCLSTME')
             ENDDO
             ELSE       CMD(DO)
                CHGVAR     VAR(&CRTMSGF) VALUE('A_MSG_GER')
                CHGVAR     VAR(&PNLGRP ) VALUE('RUNCLSTMP')
                CHGVAR     VAR(&CMD    ) VALUE('RUNCLSTM')
             ENDDO

     /* -------------------------------- */
     /*  Delete old objects              */
     /* -------------------------------- */
             DLTCMD    CMD(&TOLIB/&CMD)
             MONMSG     MSGID(CPF2105)

             DLTCMD    CMD(&TOLIB/RUNCLSTME)
             MONMSG     MSGID(CPF2105)

             DLTPGM    PGM(&TOLIB/RUNCLSTM)
             MONMSG     MSGID(CPF2105)

             DLTSRVPGM  SRVPGM(&TOLIB/RUNCLSTMS1)
             MONMSG     MSGID(CPF2105)

             DLTMSGF    MSGF(&TOLIB/&MSGF)
             MONMSG     MSGID(CPF2105)

             DLTMSGF    MSGF(&TOLIB/RUNCLSTME)
             MONMSG     MSGID(CPF2105)

             DLTPNLGRP  PNLGRP(&TOLIB/&PNLGRP)
             MONMSG     MSGID(CPF2105)

             DLTPNLGRP  PNLGRP(&TOLIB/RUNCLSTMPE)
             MONMSG     MSGID(CPF2105)

             DLTF       FILE(&TOLIB/XDERRCODE)
             MONMSG     MSGID(CPF2105)

             DLTF       FILE(&TOLIB/XDMSG)
             MONMSG     MSGID(CPF2105)

             DLTF       FILE(&TOLIB/XDQOBJ)
             MONMSG     MSGID(CPF2105)

     /* -------------------------------- */
     /*  Create message file             */
     /* -------------------------------- */
             CRTMSGF    MSGF(&TOLIB/&MSGF) +
                          TEXT('Tool: RUNCLSTM   (Run CL Statement)')

             CRTCLPGM   PGM(QTEMP/&CRTMSGF) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*PGM) +
                          OPTION(*LSTDBG) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(&CRTMSGF  ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

             CALL       PGM(QTEMP/&CRTMSGF) PARM(&TOLIB)
             DLTPGM     PGM(QTEMP/&CRTMSGF)

     /* -------------------------------- */
     /*  Create modules                  */
     /* -------------------------------- */
             CRTRPGMOD  MODULE(&TOLIB/RUNCLSTMS1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          TEXT(*SRCMBRTXT) DBGVIEW(*LIST) +
                          TGTRLS(&TGTRLS) +
                          TRUNCNBR(*NO)
             DLTSPLF    FILE(RUNCLSTMS1) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

             CRTRPGMOD MODULE(&TOLIB/RUNCLSTMS2) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          TEXT(*SRCMBRTXT) DBGVIEW(*LIST) +
                          TGTRLS(&TGTRLS) +
                          TRUNCNBR(*NO)
             DLTSPLF    FILE(RUNCLSTMS2) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

             CRTRPGMOD MODULE(&TOLIB/RUNCLSTMR1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          TEXT(*SRCMBRTXT) DBGVIEW(*LIST) +
                          TGTRLS(&TGTRLS) +
                          TRUNCNBR(*NO)
             DLTSPLF    FILE(RUNCLSTMR1) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create service programs         */
     /* -------------------------------- */
             CRTSRVPGM  SRVPGM(&TOLIB/RUNCLSTMS1) +
                          MODULE(&TOLIB/RUNCLSTMS1 +
                                 &TOLIB/RUNCLSTMS2 ) +
                          SRCFILE(&TOLIB/QRUNCLSTM) +
                          SRCMBR(RUNCLSTMF ) +
                          ACTGRP(*CALLER) +
                          DETAIL(*BASIC) +
                          TEXT('Tool: RUNCLSCT   (Run CL Statement   )')
             DLTSPLF    FILE(RUNCLSTMS1) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create programs                 */
     /* -------------------------------- */
             CRTPGM     PGM(&TOLIB/RUNCLSTM) +
                          MODULE(&TOLIB/RUNCLSTMR1) +
                          BNDSRVPGM(&TOLIB/RUNCLSTMS1) +
                          BNDDIR(QC2LE) +
                          ACTGRP(*NEW) +
                          TGTRLS(&TGTRLS) +
                          DETAIL(*BASIC)
             DLTSPLF    FILE(RUNCLSTM  ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Panel groups                    */
     /* -------------------------------- */
             CRTPNLGRP PNLGRP(&TOLIB/RUNCLSTMP) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(&PNLGRP)
             DLTSPLF    FILE(RUNCLSTMP ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create commands                 */
     /* -------------------------------- */
             CRTCMD     CMD(&TOLIB/RUNCLSTM) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(&CMD) +
                          PGM(&TOLIB/RUNCLSTM)                   +
                          HLPSCHIDX(*NONE)                       +
                          HLPPNLGRP(*LIBL/RUNCLSTMP)             +
                          HLPID(RUNCLSTM  )                      +
                          PRDLIB(&TOLIB)
             DLTSPLF    FILE(&CMD      ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Delete obsolete objects         */
     /* -------------------------------- */
             DLTMOD    MODULE(&TOLIB/RUNCLSTMS1)
             DLTMOD    MODULE(&TOLIB/RUNCLSTMS2)
             DLTMOD    MODULE(&TOLIB/RUNCLSTMR1)

             ENDPGM

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0001                    */
     /* Länge ausserhalb des gültigen Bereichs.                     */
     /*-------------------------------------------------------------*/

             PGM        PARM(&LI)

             DCL        VAR(&LI) TYPE(*CHAR) LEN(10)

             RMVMSGD MSGID(USR0001) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0001) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Value for length out of range.'                                      +
                ) +
                SEV(00) +
     /*   Keine Ersatzvariablen definiert!                          */ +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0002                    */
     /* Fehler bei Befehlsausführung in Zeile &1.                   */
     /*-------------------------------------------------------------*/

             RMVMSGD MSGID(USR0002) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0002) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Error at sequence number &1.'                                        +
                ) +
                SECLVL(+
'Befehl  . . . . : &2'                                                +
                ) +
                SEV(30) +
                FMT( +
                    (*DEC 006 2) +
                    (*CHAR 512) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0003                    */
     /* Die Betriebsart &1 ist bereits eingestellt worden.          */
     /*-------------------------------------------------------------*/

             RMVMSGD MSGID(USR0003) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0003) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Mode &1 is already activ.'                                           +
                ) +
                SECLVL(+
'Solution  . . . :   Make sure that the tag &2 is not been used immedi-
ately after each other. The tag &2 always must be followed by the tag -
&3.'                                                                  +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0004                    */
     /* Die Betriebsart &1 ist bereits eingestellt worden.          */
     /*-------------------------------------------------------------*/

             RMVMSGD MSGID(USR0004) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0004) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Mode &1 is already activ.'                                           +
                ) +
                SECLVL(+
'Solution  . . . :   Make sure that the tag &2 is not been used immedi-
ately after each other. The tag &2 always must be preceded by the tag -
&3.'                                                                  +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

             RCLRSC LVL(*)

             ENDPGM

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0001                    */
     /* Länge ausserhalb des gültigen Bereichs.                     */
     /*-------------------------------------------------------------*/

             PGM        PARM(&LI)

             DCL        VAR(&LI) TYPE(*CHAR) LEN(10)

             RMVMSGD MSGID(USR0001) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0001) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Länge ausserhalb des gültigen Bereichs.'                             +
                ) +
                SEV(00) +
     /*   Keine Ersatzvariablen definiert!                          */ +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0002                    */
     /* Fehler bei Befehlsausführung in Zeile &1.                   */
     /*-------------------------------------------------------------*/

             RMVMSGD MSGID(USR0002) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0002) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Fehler bei Befehlsausführung in Zeile &1.'                           +
                ) +
                SECLVL(+
'Befehl  . . . . : &2'                                                +
                ) +
                SEV(30) +
                FMT( +
                    (*DEC 006 2) +
                    (*CHAR 512) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0003                    */
     /* Die Betriebsart &1 ist bereits eingestellt worden.          */
     /*-------------------------------------------------------------*/

             RMVMSGD MSGID(USR0003) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0003) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Die Betriebsart &1 ist bereits eingestellt worden.'                  +
                ) +
                SECLVL(+
'Maßnahmen . . . :   Stellen Sie sicher, dass die Anweisung &2 nicht z-
weimal hintereinander verwendet wird. Die Anweisung &2 muss immer mit -
&3 beendet werden.'                                                   +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
     /*   Cmd-ADDMSGD für Message-ID :   USR0004                    */
     /* Die Betriebsart &1 ist bereits eingestellt worden.          */
     /*-------------------------------------------------------------*/

             RMVMSGD MSGID(USR0004) MSGF(&LI/RUNCLSTM)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(USR0004) +
                MSGF(&LI/RUNCLSTM) +
                MSG(+
'Die Betriebsart &1 ist bereits eingestellt worden.'                  +
                ) +
                SECLVL(+
'Maßnahmen . . . :   Stellen Sie sicher, dass die Anweisung &2 nicht z-
weimal hintereinander verwendet wird. Die Anweisung &2 muss immer mit -
&3 eingeleitet werden.'                                               +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 010) +
                    (*CHAR 010) +
                    (*CHAR 010) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

             RCLRSC LVL(*)

             ENDPGM

**free
/if NOT DEFINED(errCode_t )
/define errCode_t
//===============================================================*
//  API error code                                               *
//===============================================================*
dcl-ds errCode_t qualified based(pDummy);
  bytPrv     int(10);
  bytAvl     int(10);
  excID      char(7);
  reserved_1 char(1);
  excDta     char(256);
end-ds;

/endif

**free
/if NOT DEFINED(msg_t     )
/define msg_t
// ============================================================= *
//   Message structure                                           *
// ============================================================= *

dcl-ds msg_t qualified based(pDummy);
/if defined(*V5R3M0)
  ID   likeds(msgID_t);
/else
  ID   char(7);
/endif
  data char(512);
  type char(10);
  file char(10);
  lib  char(10);
end-ds;

/if defined(*V5R3M0)
dcl-ds msgID_t qualified based(pDummy);
  prefix char(3);
  nbr    zoned(4);
end-ds;
/endif

/endif

**free
/if NOT DEFINED(qObj_t    )
/define qObj_t
// ============================================================= *
//   Qualified object name                                       *
//===============================================================*

dcl-ds qObj_t qualified based(pDummy);
  name char(10);
  lib  char(10);
end-ds;

/endif

     /* =================================================================== */
     /*                                                                     */
     /*  Kurzdokumentation :                                                */
     /*                                                                     */
     /*  Bereich . . . : RUNCLSTM                                           */
     /*  Objekt  . . . : RUNCLSTMF                                          */
     /*  Beschreibung  : Tool: RUNCLSTM   (Run CL Statements         )      */
     /*  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      */
     /*  Datum . . . . : 03.08.2000                                         */
     /*                                                                     */
     /* =================================================================== */

             STRPGMEXP  PGMLVL(*CURRENT) LVLCHK(*YES) SIGNATURE(*GEN)

                EXPORT SYMBOL(f_cmpMonMsgId  )
                EXPORT SYMBOL(f_execute      )
                EXPORT SYMBOL(f_opnSql       )
                EXPORT SYMBOL(f_executeSQL   )
                EXPORT SYMBOL(p_cloSql       )
                EXPORT SYMBOL(f_exist        )
                EXPORT SYMBOL(f_fmtCmd       )
                EXPORT SYMBOL(f_getApiErrMsg )
                EXPORT SYMBOL(f_isApiErr     )
                EXPORT SYMBOL(f_newErrCode   )
                EXPORT SYMBOL(f_newMsg       )
                EXPORT SYMBOL(f_right        )
                EXPORT SYMBOL(f_rmvRemCl     )

                EXPORT SYMBOL(p_endPgmAbn    )
                EXPORT SYMBOL(p_sndPgmMsg    )

                EXPORT SYMBOL(p_setMsgFile   )
                EXPORT SYMBOL(f_getMsgFile   )
                EXPORT SYMBOL(f_getMsgFileLib)

             ENDPGMEXP

**free
// =================================================================== *
//                                                                     *
//  Kurzdokumentation :                                                *
//                                                                     *
//  Bereich . . . : RUNCLSTM                                           *
//  Objekt  . . . : RUNCLSTMG1                                         *
//  Beschreibung  : Tool: RUNCLSTM   (Run CL Statements         )      *
//  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      *
//  Datum . . . . : 03.08.2000                                         *
//                                                                     *
// =================================================================== *

//===============================================================*
//  Exported Prototypes
//===============================================================*

dcl-pr f_rmvRemCl varchar(32767);
  i_clString varchar(32767) value;
end-pr;

//  Öffnen SQL
dcl-pr f_opnSQL like(bool_t);
  i_naming like(naming_t) const;
  o_msg    likeds(msg_t);
end-pr;

dcl-pr f_executeSQL opdesc like(bool_t);
  i_sqlStmt like(capcmd_t) options(*varsize) const;
  o_msg     likeds(msg_t);
end-pr;

//  Schließen SQL
dcl-pr p_cloSQL;
end-pr;

dcl-pr f_execute opdesc like(bool_t);
  i_cmd       like(capcmd_t) options(*varsize) const;
  o_msg       likeds(msg_t) options(*nopass: *omit);
  i_typCmdPrc like(int4_t) options(*nopass) const;
end-pr;

dcl-pr f_fmtCmd like(capcmd_t);
  i_cmd like(capcmd_t) value;
end-pr;

dcl-pr f_cmpMonMsgID like(bool_t);
  i_msgId    like(msg_t.ID) value;
  i_monMsgId like(msg_t.ID) value;
end-pr;

dcl-pr f_newErrCode like(errCode_t);
  i_monErr like(bool_t) value;
end-pr;

dcl-pr f_getAPIErrMsg likeds(msg_t);
  i_errorCode like(errCode_t) value;
end-pr;

dcl-pr f_isAPIErr like(bool_t);
  i_errorCode like(errCode_t) value;
end-pr;

dcl-pr f_newMsg likeds(msg_t);
  i_msgID   like(msg_t.ID) value;
  // optionale Parametergruppe 1
  i_msgType like(msg_t.type) options(*nopass) value;
  // optionale Parametergruppe 2
  i_msgDta  like(msg_t.data) options(*nopass: *omit) const;
  // optionale Parametergruppe 3
  i_msgF    like(msg_t.file) options(*nopass) value;
  // optionale Parametergruppe 4
  i_msgL    like(msg_t.lib) options(*nopass) value;
end-pr;

dcl-pr f_right varchar(32767);
  i_string varchar(32767) value;
  i_rLen   like(int4_t) options(*nopass) value;
end-pr;

dcl-pr p_endPgmAbn;
  i_msg likeds(msg_t) value;
end-pr;

dcl-pr p_sndPgmMsg;
  i_msg    likeds(msg_t) value;
  // optionale Parametergruppe 1
  i_toStkC like(int4_t) options(*nopass) value;
  // optionale Parametergruppe 2
  i_toProc like(proc_t) options(*nopass) value;
  // optionale Parametergruppe 3
  i_toMod  like(mod_t) options(*nopass: *omit) const;
  // optionale Parametergruppe 4
  i_toPgm  like(pgm_t) options(*nopass) value;
end-pr;

dcl-pr f_exist like(bool_t);
  i_obj     like(obj_t) const;
  i_lib     like(lib_t) options(*omit) const;
  i_objType like(objType_t) const;
  i_mbr     like(mbr_t) options(*omit) const;
  o_msg     likeds(msg_t) options(*nopass);
end-pr;
//  Set Message file
dcl-pr p_setMsgFile;
  i_msgF    like(msg_t.file) value;
  i_msgFLib like(msg_t.lib) value;
end-pr;

//  Get Message file
dcl-pr f_getMsgFile like(msg_t.file);
end-pr;

//  Get Message file library
dcl-pr f_getMsgFileLib like(msg_t.lib);
end-pr;

**free
